import React from "react"

const Equipe = (props) => {
  return (
    <div>
      <Sobre nome="{props.nome}" cargo="{props.cargo}" idade="{props.idade}"  />
      <Social fb="{props.facebook}" /> 
    </div>
  )
}

const Sobre = (props) => {
  return (
    <div>
      <h1>Nome: {props.nome}</h1>
      <h2>Cargo: {props.cargo}</h2>
      <h3>Idade: {props.idade}</h3>
    </div>
  )
}

const Social = (props) => {
  return (
    <div>
      <a href="{props.fb}">facebook</a>
    </div>
  )
}

function App() {
  return (
    <div>
      <Equipe/>
    </div>
  )
}

export default App;
